#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,C; scanf("%lld %lld %lld", &A, &B, &C);
        if(A==B+C || B==A+C || C==A+B) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

